import React from 'react';

import './Cdc.css';

const Cdc = () => {
  const [r1, setR1] = useState(true);
  const [r2, setR2] = useState(false);
  const [r3, setR3] = useState(false);

  const clkHnd1 = () => {
    setR1(true);
    setR2(false);
    setR3(false);
   
};

const clkHnd2 = () => {
    setR1(false);
    setR2(true);
    setR3(false);
   
};

const clkHnd3 = () => {
    setR1(false);
    setR2(false);
    setR3(true);
    
};
  return (
    <div>Cdc</div>
  )
}

export default Cdc
